code.python:
def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

code.javascript:
function factorial(n) {
  if (n <= 1) return 1;
  return n * factorial(n - 1);
}

code.java:
int factorial(int n) {
    if (n <= 1) return 1;
